#!/usr/bin/env node
/**
 * sync-trad-redirects-cf.mjs
 *
 * Syncs the traditional-word redirect map produced by `npm run p2-words` to a
 * Cloudflare Bulk Redirect List so that requests to
 *
 *   words.servewell.net/<traditional-word>
 *
 * receive a proper 301 redirect (at the CDN level, before R2 is hit) pointing
 * to the matching literal word-study page.
 *
 * The source of truth is src/json-Phase2/words/_traditional-redirects.json
 * (generated by generateWordStudyJson.ts and checked in so git tracks changes).
 *
 * A fingerprint of that file is stored in dist/.trad-redirects-cf-synced after
 * each successful sync.  pre-deploy.mjs compares the fingerprints and prompts
 * to run this script only when the redirect map has changed.
 *
 * One-time setup:
 *   1. Create the Bulk Redirect List in the Cloudflare dashboard or via this
 *      script (it creates the list automatically on first run).
 *   2. After the list is created a Bulk Redirect Rule must be attached to your
 *      zone.  The script will print the list ID so you can create the rule in
 *      the dashboard:  Security → WAF → Bulk Redirects → Create Bulk Redirect Rule.
 *      (The API for creating rules requires a zone-level token; the script only
 *      needs an account-level token to manage the list.)
 *
 * Required environment variables:
 *   CLOUDFLARE_ACCOUNT_ID   — Cloudflare account ID
 *   CLOUDFLARE_API_TOKEN    — API token with "Account Firewall Access Rules: Edit"
 *                             permission (or "Zone: Edit" if you also create rules)
 *
 * Optional environment variables:
 *   CF_REDIRECT_LIST_NAME   — Name for the Bulk Redirect List (default: "servewell_word_redirects")
 *   WORDS_DOMAIN            — Domain for the redirect source (default: "words.servewell.net")
 *
 * Run: npm run deploy:trad-redirects-cf
 */

import { createHash } from 'node:crypto';
import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const ROOT = join(dirname(__filename), '..');

// ---------------------------------------------------------------------------
// Load .env
// ---------------------------------------------------------------------------
const envFile = join(ROOT, '.env');
if (existsSync(envFile)) {
  for (const line of readFileSync(envFile, 'utf8').split('\n')) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eq = trimmed.indexOf('=');
    if (eq < 0) continue;
    const key = trimmed.slice(0, eq).trim();
    const val = trimmed.slice(eq + 1).trim();
    if (key && val && !process.env[key]) process.env[key] = val;
  }
}

const ACCOUNT_ID   = process.env.CLOUDFLARE_ACCOUNT_ID;
const API_TOKEN    = process.env.CLOUDFLARE_API_TOKEN;
const LIST_NAME    = process.env.CF_REDIRECT_LIST_NAME ?? 'servewell_word_redirects';
const WORDS_DOMAIN = process.env.WORDS_DOMAIN ?? 'words.servewell.net';

if (!ACCOUNT_ID || !API_TOKEN) {
  console.error('Error: CLOUDFLARE_ACCOUNT_ID and CLOUDFLARE_API_TOKEN must be set.');
  console.error('Add them to your .env file or export them as shell variables.');
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Paths
// ---------------------------------------------------------------------------
const REDIRECTS_FILE = join(ROOT, 'src/json-Phase2/words/_traditional-redirects.json');
const DIST_DIR       = join(ROOT, 'dist');
const SYNCED_MARKER  = join(DIST_DIR, '.trad-redirects-cf-synced');

if (!existsSync(REDIRECTS_FILE)) {
  console.error(`Redirects file not found: ${REDIRECTS_FILE}`);
  console.error('Run "npm run p2-words" first.');
  process.exit(1);
}

const redirectsJson = readFileSync(REDIRECTS_FILE, 'utf8');
const currentFingerprint = createHash('sha256').update(redirectsJson).digest('hex').slice(0, 16);

// Check if already synced
const syncedFingerprint = existsSync(SYNCED_MARKER)
  ? readFileSync(SYNCED_MARKER, 'utf8').trim()
  : '';

if (syncedFingerprint === currentFingerprint) {
  console.log('Traditional word redirects are already in sync with Cloudflare. Nothing to do.');
  process.exit(0);
}

// ---------------------------------------------------------------------------
// Parse redirect entries (only 'redirect' type stubs — crossrefs are handled
// by the HTML word pages themselves, not by CF Bulk Redirects)
// ---------------------------------------------------------------------------
/** @type {Record<string, { target: string; count: number; type: 'redirect' | 'crossref' }>} */
const redirectsData = JSON.parse(redirectsJson);
const redirectEntries = Object.entries(redirectsData)
  .filter(([, entry]) => entry.type === 'redirect')
  .map(([lemma, entry]) => ({ lemma, target: entry.target }));

console.log(`Loaded ${redirectEntries.length} redirect entries (${Object.keys(redirectsData).length} total)`);

// ---------------------------------------------------------------------------
// CF API helpers
// ---------------------------------------------------------------------------
const CF_BASE = `https://api.cloudflare.com/client/v4/accounts/${ACCOUNT_ID}`;

async function cfFetch(path, options = {}) {
  const url = `${CF_BASE}${path}`;
  const res = await fetch(url, {
    ...options,
    headers: {
      'Authorization': `Bearer ${API_TOKEN}`,
      'Content-Type': 'application/json',
      ...(options.headers ?? {}),
    },
  });
  const body = await res.json();
  if (!body.success) {
    throw new Error(`CF API error at ${path}: ${JSON.stringify(body.errors)}`);
  }
  return body;
}

// ---------------------------------------------------------------------------
// Get or create the redirect list
// ---------------------------------------------------------------------------
console.log(`\nLooking for existing list "${LIST_NAME}"...`);

const listsRes = await cfFetch('/rules/lists');
let list = (listsRes.result ?? []).find(l => l.name === LIST_NAME);

if (!list) {
  console.log(`List not found — creating "${LIST_NAME}"...`);
  const createRes = await cfFetch('/rules/lists', {
    method: 'POST',
    body: JSON.stringify({
      name: LIST_NAME,
      kind: 'redirect',
      description: 'Traditional Bible word redirects → literal word study pages on words.servewell.net',
    }),
  });
  list = createRes.result;
  console.log(`Created list with ID: ${list.id}`);
  console.log(`\nNOTE: You must attach this list to a Bulk Redirect Rule in the Cloudflare`);
  console.log(`dashboard (or via API) for the redirects to take effect.`);
  console.log(`  Dashboard: Account Home → Bulk Redirects → Create Bulk Redirect Rule`);
  console.log(`  List ID: ${list.id}\n`);
} else {
  console.log(`Found existing list with ID: ${list.id}`);
}

// ---------------------------------------------------------------------------
// Replace all items in the list
// ---------------------------------------------------------------------------
// CF Bulk Redirect source_url must be the full URL without scheme, e.g.
//   words.servewell.net/grace  (no https://)
const items = redirectEntries.map(({ lemma, target }) => ({
  redirect: {
    source_url: `${WORDS_DOMAIN}/${encodeURIComponent(lemma)}`,
    target_url: `https://${WORDS_DOMAIN}/${encodeURIComponent(target)}`,
    status_code: 301,
    include_subdomains: false,
    preserve_query_string: false,
    subpath_matching: false,
  },
}));

console.log(`\nPushing ${items.length} redirect items to list "${LIST_NAME}" (id: ${list.id})...`);

// CF allows at most 500 items per PUT request — batch if needed
const BATCH_SIZE = 500;
if (items.length > BATCH_SIZE) {
  // Delete all existing items first, then add in batches
  await cfFetch(`/rules/lists/${list.id}/items`, {
    method: 'DELETE',
    body: JSON.stringify({ items: [] }), // empty array = delete all
  });
  for (let i = 0; i < items.length; i += BATCH_SIZE) {
    const batch = items.slice(i, i + BATCH_SIZE);
    await cfFetch(`/rules/lists/${list.id}/items`, {
      method: 'POST',
      body: JSON.stringify(batch),
    });
    console.log(`  Uploaded batch ${Math.floor(i / BATCH_SIZE) + 1} / ${Math.ceil(items.length / BATCH_SIZE)}`);
  }
} else {
  // PUT replaces all items atomically
  await cfFetch(`/rules/lists/${list.id}/items`, {
    method: 'PUT',
    body: JSON.stringify(items),
  });
}

console.log(`\nDone. ${items.length} redirect items pushed to Cloudflare Bulk Redirect List.`);

// ---------------------------------------------------------------------------
// Update the synced marker
// ---------------------------------------------------------------------------
if (!existsSync(DIST_DIR)) mkdirSync(DIST_DIR, { recursive: true });
writeFileSync(SYNCED_MARKER, currentFingerprint, 'utf8');
console.log(`Updated ${SYNCED_MARKER}`);
